import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  IconButton,
  Tooltip,
  CircularProgress,
  Alert
} from '@mui/material';
import {
  Close,
  Refresh
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const FinishedOperationsModal = ({ open, onClose, hideValues = false }) => {
  const [positions, setPositions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [refreshing, setRefreshing] = useState(false);

  const loadFinishedPositions = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await dashboardService.getFinishedPositions();
      console.log('Dados recebidos:', response); // Debug
      if (response.success && Array.isArray(response.data)) {
        setPositions(response.data);
      } else {
        console.error('Formato de resposta inválido:', response);
        setError('Erro no formato dos dados recebidos');
      }
    } catch (error) {
      console.error('Erro ao carregar posições:', error);
      setError('Erro ao carregar posições finalizadas');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (open) {
      loadFinishedPositions();
    }
  }, [open]);

  const handleRefresh = async () => {
    setRefreshing(true);
    await loadFinishedPositions();
    setRefreshing(false);
  };

  const formatCurrency = (value) => {
    if (!value) return '0.0000';
    return Number(value).toFixed(4);
  };

  const formatDate = (timestamp) => {
    if (!timestamp) return '-';
    return new Date(Number(timestamp)).toLocaleString();
  };

  const getColorByValue = (value) => {
    if (!value) return 'text.primary';
    const numValue = Number(value);
    return numValue > 0 ? 'success.main' : numValue < 0 ? 'error.main' : 'text.primary';
  };

  const getSideColor = (side) => {
    return side?.toLowerCase() === 'long' ? 'success.main' : 'error.main';
  };

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="lg"
      fullWidth
    >
      <DialogTitle>
        <Box display="flex" justifyContent="space-between" alignItems="center">
          <Typography variant="h6">Operações Finalizadas</Typography>
          <Box>
            <Tooltip title="Atualizar">
              <IconButton onClick={handleRefresh} disabled={refreshing}>
                <Refresh />
              </IconButton>
            </Tooltip>
            <Tooltip title="Fechar">
              <IconButton onClick={onClose}>
                <Close />
              </IconButton>
            </Tooltip>
          </Box>
        </Box>
      </DialogTitle>
      <DialogContent>
        {loading ? (
          <Box display="flex" justifyContent="center" p={3}>
            <CircularProgress />
          </Box>
        ) : error ? (
          <Alert severity="error">{error}</Alert>
        ) : positions.length === 0 ? (
          <Alert severity="info">Nenhuma operação finalizada encontrada.</Alert>
        ) : (
          <TableContainer component={Paper}>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Par</TableCell>
                  <TableCell>Lado</TableCell>
                  <TableCell>Tamanho</TableCell>
                  <TableCell>Alavancagem</TableCell>
                  <TableCell>Preço Médio</TableCell>
                  <TableCell>Take Profit</TableCell>
                  <TableCell>Stop Loss</TableCell>
                  <TableCell>Lucro/Prejuízo</TableCell>
                  <TableCell>Data Criação</TableCell>
                  <TableCell>Data Fechamento</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {positions.map((position, index) => (
                  <TableRow key={`${position.symbol}-${position.cTime}-${index}`}>
                    <TableCell>{position.symbol}</TableCell>
                    <TableCell>
                      <Typography color={getSideColor(position.holdSide)}>
                        {position.holdSide?.toUpperCase()}
                      </Typography>
                    </TableCell>
                    <TableCell>{formatCurrency(position.openTotalPos)}</TableCell>
                    <TableCell>{position.leverage ? `${position.leverage}x` : '-'}</TableCell>
                    <TableCell>{formatCurrency(position.openAvgPrice)}</TableCell>
                    <TableCell>{formatCurrency(position.takeProfit) || '-'}</TableCell>
                    <TableCell>{formatCurrency(position.stopLoss) || '-'}</TableCell>
                    <TableCell>
                      <Typography color={getColorByValue(position.netProfit)}>
                        {formatCurrency(position.netProfit)} USDT
                      </Typography>
                    </TableCell>
                    <TableCell>{formatDate(position.cTime)}</TableCell>
                    <TableCell>{formatDate(position.uTime)}</TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        )}
      </DialogContent>
    </Dialog>
  );
};

export default FinishedOperationsModal;
